using ByteForge.Toolkit;
using System.Net.Mail;

// Create email attachment handler
var handler = new EmailAttachmentHandler();

// Process incoming email with attachments
var email = GetEmailMessage(); // Get from email server

Console.WriteLine($"Processing email from: {email.From}");
Console.WriteLine($"Subject: {email.Subject}");
Console.WriteLine($"Attachments: {email.Attachments.Count}");

// Process all attachments
var results = handler.ProcessAttachments(email.Attachments);

foreach (var result in results)
{
    if (result.IsSuccess)
    {
        Console.WriteLine($"✓ Processed: {result.OriginalFileName}");
        Console.WriteLine($"  Temp file: {result.TempFile.TemporaryFilePath}");
        Console.WriteLine($"  Size: {result.TempFile.FileSize:N0} bytes");
        Console.WriteLine($"  Content type: {result.TempFile.ContentType}");

        // Read attachment content
        byte[] content = result.TempFile.ReadAllBytes();
        ProcessAttachmentContent(content, result.TempFile.OriginalFileName);
    }
    else
    {
        Console.WriteLine($"✗ Failed: {result.OriginalFileName} - {result.ErrorMessage}");
    }
}

// Clean up temporary files
handler.CleanupTemporaryFiles();
Console.WriteLine("Temporary files cleaned up");

void ProcessAttachmentContent(byte[] content, string fileName)
{
    string extension = Path.GetExtension(fileName).ToLower();

    switch (extension)
    {
        case ".txt":
            string text = Encoding.UTF8.GetString(content);
            Console.WriteLine($"Text content: {text.Substring(0, Math.Min(100, text.Length))}...");
            break;

        case ".pdf":
            Console.WriteLine($"PDF document: {content.Length:N0} bytes");
            // Process PDF content
            break;

        case ".xlsx":
            Console.WriteLine($"Excel document: {content.Length:N0} bytes");
            // Process Excel content
            break;

        default:
            Console.WriteLine($"Binary content: {content.Length:N0} bytes");
            break;
    }
}

// Create handler with custom settings
var handler = new EmailAttachmentHandler();

// Define acceptable file types
var acceptedExtensions = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
{
    ".pdf", ".docx", ".xlsx", ".txt", ".csv", ".jpg", ".png"
};

// Define size limits (50 MB)
const long MAX_FILE_SIZE = 50 * 1024 * 1024;

var processedAttachments = new List<AttachmentProcessResult>();
var skippedFiles = new List<SkippedFile>();

foreach (var attachment in email.Attachments)
{
    // Check file extension
    string extension = Path.GetExtension(attachment.Name ?? "").ToLower();
    if (!acceptedExtensions.Contains(extension))
    {
        skippedFiles.Add(new SkippedFile
        {
            FileName = attachment.Name,
            Reason = $"Unsupported file type: {extension}",
            SkippedAt = DateTime.Now
        });
        continue;
    }

    // Check file size
    if (attachment.ContentStream.Length > MAX_FILE_SIZE)
    {
        skippedFiles.Add(new SkippedFile
        {
            FileName = attachment.Name,
            Reason = $"File too large: {attachment.ContentStream.Length:N0} bytes",
            SkippedAt = DateTime.Now
        });
        continue;
    }

    // Check for dangerous file names
    if (IsDangerousFileName(attachment.Name))
    {
        skippedFiles.Add(new SkippedFile
        {
            FileName = attachment.Name,
            Reason = "Potentially dangerous file name",
            SkippedAt = DateTime.Now
        });
        continue;
    }

    // Process accepted attachment
    try
    {
        var result = handler.ProcessAttachment(attachment);
        processedAttachments.Add(result);

        if (result.IsSuccess)
        {
            Console.WriteLine($"✓ Processed: {result.OriginalFileName} ({result.TempFile.FileSize:N0} bytes)");
        }
        else
        {
            Console.WriteLine($"⚠ Processing error: {result.OriginalFileName} - {result.ErrorMessage}");
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"✗ Exception processing {attachment.Name}: {ex.Message}");
        skippedFiles.Add(new SkippedFile
        {
            FileName = attachment.Name,
            Reason = $"Processing exception: {ex.Message}",
            SkippedAt = DateTime.Now
        });
    }
}

// Report processing results
Console.WriteLine($"\nProcessing Summary:");
Console.WriteLine($"  Processed: {processedAttachments.Count(r => r.IsSuccess)} files");
Console.WriteLine($"  Failed: {processedAttachments.Count(r => !r.IsSuccess)} files");
Console.WriteLine($"  Skipped: {skippedFiles.Count} files");

// Show skipped files
if (skippedFiles.Any())
{
    Console.WriteLine($"\nSkipped files:");
    foreach (var skipped in skippedFiles)
    {
        Console.WriteLine($"  - {skipped.FileName}: {skipped.Reason}");
    }
}

bool IsDangerousFileName(string fileName)
{
    if (string.IsNullOrEmpty(fileName))
        return false;

    var dangerousExtensions = new[] { ".exe", ".bat", ".cmd", ".scr", ".vbs", ".js" };
    string extension = Path.GetExtension(fileName).ToLower();

    return dangerousExtensions.Contains(extension) ||
           fileName.Contains("..") ||  // Directory traversal
           Path.GetInvalidFileNameChars().Any(fileName.Contains);
}

public class EmailBatchProcessor
{
    private readonly EmailAttachmentHandler _attachmentHandler;

    public EmailBatchProcessor()
    {
        _attachmentHandler = new EmailAttachmentHandler();
    }

    public async Task ProcessEmailBatch(IEnumerable<MailMessage> emails)
    {
        var allEmails = emails.ToList();
        Console.WriteLine($"Processing batch of {allEmails.Count} emails");

        int processedEmails = 0;
        int totalAttachments = 0;
        int successfulAttachments = 0;
        var allTempFiles = new List<TempFileAttachment>();

        try
        {
            foreach (var email in allEmails)
            {
                processedEmails++;
                Console.WriteLine($"\n[{processedEmails}/{allEmails.Count}] Processing email from: {email.From}");

                if (!email.Attachments.Any())
                {
                    Console.WriteLine("  No attachments - skipping");
                    continue;
                }

                Console.WriteLine($"  Found {email.Attachments.Count} attachments");
                totalAttachments += email.Attachments.Count;

                // Process attachments for this email
                var results = _attachmentHandler.ProcessAttachments(email.Attachments);

                foreach (var result in results)
                {
                    if (result.IsSuccess)
                    {
                        successfulAttachments++;
                        allTempFiles.Add(result.TempFile);
                        Console.WriteLine($"    ✓ {result.OriginalFileName} ({result.TempFile.FileSize:N0} bytes)");

                        // Process attachment based on type
                        await ProcessAttachmentByType(result);
                    }
                    else
                    {
                        Console.WriteLine($"    ✗ {result.OriginalFileName}: {result.ErrorMessage}");
                    }
                }

                // Show progress
                double progress = (double)processedEmails / allEmails.Count * 100;
                Console.WriteLine($"  Progress: {progress:F1}% ({processedEmails}/{allEmails.Count} emails)");
            }

            // Final summary
            Console.WriteLine($"\n=== Batch Processing Complete ===");
            Console.WriteLine($"Emails processed: {processedEmails}");
            Console.WriteLine($"Total attachments: {totalAttachments}");
            Console.WriteLine($"Successful extractions: {successfulAttachments}");
            Console.WriteLine($"Success rate: {(double)successfulAttachments / totalAttachments:P1}");

            // Generate processing report
            await GenerateProcessingReport(allTempFiles);
        }
        finally
        {
            // Always clean up temporary files
            Console.WriteLine($"\nCleaning up {allTempFiles.Count} temporary files...");
            _attachmentHandler.CleanupTemporaryFiles();
            Console.WriteLine("Cleanup complete");
        }
    }

    private async Task ProcessAttachmentByType(AttachmentProcessResult result)
    {
        string extension = Path.GetExtension(result.OriginalFileName).ToLower();

        switch (extension)
        {
            case ".csv":
                await ProcessCsvFile(result.TempFile);
                break;

            case ".xlsx":
                await ProcessExcelFile(result.TempFile);
                break;

            case ".pdf":
                await ProcessPdfFile(result.TempFile);
                break;

            case ".txt":
                await ProcessTextFile(result.TempFile);
                break;

            default:
                await ProcessGenericFile(result.TempFile);
                break;
        }
    }

    private async Task ProcessCsvFile(TempFileAttachment tempFile)
    {
        Console.WriteLine($"      Processing CSV: {tempFile.OriginalFileName}");

        try
        {
            string content = tempFile.ReadAsText();
            string[] lines = content.Split('\n');

            Console.WriteLine($"      CSV has {lines.Length} lines");

            // Process CSV data
            if (lines.Length > 1)
            {
                string header = lines[0].Trim();
                Console.WriteLine($"      Header: {header}");

                // Save to permanent location for further processing
                string permanentPath = Path.Combine(@"C:\ProcessedFiles\CSV", 
                    $"{DateTime.Now:yyyyMMdd_HHmmss}_{tempFile.OriginalFileName}");

                Directory.CreateDirectory(Path.GetDirectoryName(permanentPath));
                File.Copy(tempFile.TemporaryFilePath, permanentPath);
                Console.WriteLine($"      Saved to: {permanentPath}");
            }
        }
        catch (Exception ex)
        {
            Console.WriteLine($"      Error processing CSV: {ex.Message}");
        }
    }

    private async Task ProcessExcelFile(TempFileAttachment tempFile)
    {
        Console.WriteLine($"      Processing Excel: {tempFile.OriginalFileName}");

        // Save to dedicated Excel processing folder
        string permanentPath = Path.Combine(@"C:\ProcessedFiles\Excel", 
            $"{DateTime.Now:yyyyMMdd_HHmmss}_{tempFile.OriginalFileName}");

        Directory.CreateDirectory(Path.GetDirectoryName(permanentPath));
        File.Copy(tempFile.TemporaryFilePath, permanentPath);
        Console.WriteLine($"      Saved to: {permanentPath}");
    }

    private async Task ProcessPdfFile(TempFileAttachment tempFile)
    {
        Console.WriteLine($"      Processing PDF: {tempFile.OriginalFileName}");

        // Save to PDF archive
        string permanentPath = Path.Combine(@"C:\ProcessedFiles\PDF", 
            $"{DateTime.Now:yyyyMMdd_HHmmss}_{tempFile.OriginalFileName}");

        Directory.CreateDirectory(Path.GetDirectoryName(permanentPath));
        File.Copy(tempFile.TemporaryFilePath, permanentPath);
        Console.WriteLine($"      Saved to: {permanentPath}");
    }

    private async Task ProcessTextFile(TempFileAttachment tempFile)
    {
        Console.WriteLine($"      Processing text file: {tempFile.OriginalFileName}");

        try
        {
            string content = tempFile.ReadAsText();
            Console.WriteLine($"      Text file has {content.Length} characters");

            // Save processed text
            string permanentPath = Path.Combine(@"C:\ProcessedFiles\Text", 
                $"{DateTime.Now:yyyyMMdd_HHmmss}_{tempFile.OriginalFileName}");

            Directory.CreateDirectory(Path.GetDirectoryName(permanentPath));
            File.WriteAllText(permanentPath, content);
            Console.WriteLine($"      Saved to: {permanentPath}");
        }
        catch (Exception ex)
        {
            Console.WriteLine($"      Error processing text file: {ex.Message}");
        }
    }

    private async Task ProcessGenericFile(TempFileAttachment tempFile)
    {
        Console.WriteLine($"      Processing generic file: {tempFile.OriginalFileName}");

        // Save to general archive
        string permanentPath = Path.Combine(@"C:\ProcessedFiles\Other", 
            $"{DateTime.Now:yyyyMMdd_HHmmss}_{tempFile.OriginalFileName}");

        Directory.CreateDirectory(Path.GetDirectoryName(permanentPath));
        File.Copy(tempFile.TemporaryFilePath, permanentPath);
        Console.WriteLine($"      Saved to: {permanentPath}");
    }

    private async Task GenerateProcessingReport(List<TempFileAttachment> processedFiles)
    {
        string reportPath = Path.Combine(@"C:\ProcessedFiles\Reports", 
            $"EmailProcessingReport_{DateTime.Now:yyyyMMdd_HHmmss}.txt");

        Directory.CreateDirectory(Path.GetDirectoryName(reportPath));

        var report = new StringBuilder();
        report.AppendLine("Email Attachment Processing Report");
        report.AppendLine("==================================");
        report.AppendLine($"Generated: {DateTime.Now:yyyy-MM-dd HH:mm:ss}");
        report.AppendLine($"Total files processed: {processedFiles.Count}");
        report.AppendLine();

        // Group by file type
        var filesByType = processedFiles
            .GroupBy(f => Path.GetExtension(f.OriginalFileName).ToLower())
            .OrderByDescending(g => g.Count());

        report.AppendLine("Files by type:");
        foreach (var group in filesByType)
        {
            string extension = string.IsNullOrEmpty(group.Key) ? "(no extension)" : group.Key;
            long totalSize = group.Sum(f => f.FileSize);
            report.AppendLine($"  {extension}: {group.Count()} files, {totalSize:N0} bytes total");
        }

        report.AppendLine();
        report.AppendLine("Individual files:");
        foreach (var file in processedFiles.OrderBy(f => f.OriginalFileName))
        {
            report.AppendLine($"  {file.OriginalFileName} - {file.FileSize:N0} bytes - {file.ContentType}");
        }

        await File.WriteAllTextAsync(reportPath, report.ToString());
        Console.WriteLine($"\nProcessing report saved to: {reportPath}");
    }
}

// Usage
var emails = GetEmailsFromServer(); // Implement email retrieval
var processor = new EmailBatchProcessor();
await processor.ProcessEmailBatch(emails);

using ByteForge.Toolkit;

// Test various email formats
var emailAddresses = new[]
{
    "user@example.com",
    "user.name@example.com",
    "user+tag@example.co.uk", 
    "user@subdomain.example.com",
    "invalid@",
    "@example.com",
    "plainaddress",
    "user name@example.com",  // Invalid - spaces
    "user@",
    "user@.com",
    "valid.email-123@test-domain.co.uk"
};

Console.WriteLine("Email Validation Results:");
Console.WriteLine("========================");

foreach (var email in emailAddresses)
{
    bool isValid = MailUtil.IsValidEmailAddress(email);
    string status = isValid ? "✓ VALID" : "✗ INVALID";
    Console.WriteLine($"{status}: {email}");

    if (isValid)
    {
        try
        {
            var mailAddress = MailUtil.ParseMailAddress(email);
            Console.WriteLine($"  Parsed - Address: {mailAddress.Address}, Display: '{mailAddress.DisplayName}'");
        }
        catch (Exception ex)
        {
            Console.WriteLine($"  Parse error: {ex.Message}");
        }
    }
}

// Test parsing addresses with display names
Console.WriteLine("\nParsing addresses with display names:");
var addressesWithNames = new[]
{
    "John Doe <john@example.com>",
    "\"Jane Smith\" <jane.smith@company.com>",
    "Support Team <support@helpdesk.com>",
    "user@example.com",  // No display name
    "Invalid Format <invalid@>",
    "\"Test User\" <test@domain.co.uk>"
};

foreach (var addressString in addressesWithNames)
{
    try
    {
        var mailAddress = MailUtil.ParseMailAddress(addressString);
        Console.WriteLine($"✓ {addressString}");
        Console.WriteLine($"  Email: {mailAddress.Address}");
        Console.WriteLine($"  Display Name: '{mailAddress.DisplayName}'");
        Console.WriteLine($"  Host: {mailAddress.Host}");
        Console.WriteLine($"  User: {mailAddress.User}");
    }
    catch (Exception ex)
    {
        Console.WriteLine($"✗ {addressString}");
        Console.WriteLine($"  Error: {ex.Message}");
    }
    Console.WriteLine();
}

// Test email header encoding with international characters
var headers = new[]
{
    "Subject: Regular English Subject",
    "Subject: Café München Zürich",  // German umlauts
    "Subject: 日本語のタイトル",  // Japanese
    "Subject: Здравствуй мир",   // Russian
    "Subject: Bonjour François",  // French accents
    "From: José García <jose@example.com>",  // Spanish accents
    "Subject: Special chars: €£¥©®™"
};

Console.WriteLine("Email Header Encoding:");
Console.WriteLine("=====================");

foreach (var header in headers)
{
    Console.WriteLine($"Original: {header}");

    // Encode header for email transmission
    string encoded = MailUtil.EncodeEmailHeader(header);
    Console.WriteLine($"Encoded:  {encoded}");

    // Decode back to verify
    string decoded = MailUtil.DecodeEmailHeader(encoded);
    Console.WriteLine($"Decoded:  {decoded}");

    // Verify round-trip
    bool roundTripSuccess = header == decoded;
    Console.WriteLine($"Round-trip: {(roundTripSuccess ? "✓ SUCCESS" : "✗ FAILED")}");
    Console.WriteLine();
}

// Practical example: Sending email with international subject
var email = new MailMessage();
string originalSubject = "Café Update: München Weather Report";
email.Subject = MailUtil.EncodeEmailHeader($"Subject: {originalSubject}");
email.From = new MailAddress("system@example.com", "Weather Service");
email.To.Add("user@example.com");
email.Body = "Weather report content here...";

Console.WriteLine("Email with encoded subject prepared:");
Console.WriteLine($"  Original Subject: {originalSubject}");
Console.WriteLine($"  Encoded Subject: {email.Subject}");
Console.WriteLine($"  From: {email.From}");

// When receiving email, decode the subject
string receivedSubject = email.Subject;
if (receivedSubject.StartsWith("Subject: "))
{
    receivedSubject = receivedSubject.Substring("Subject: ".Length);
}
string decodedSubject = MailUtil.DecodeEmailHeader($"Subject: {receivedSubject}");
if (decodedSubject.StartsWith("Subject: "))
{
    decodedSubject = decodedSubject.Substring("Subject: ".Length);
}

Console.WriteLine($"  Decoded Subject: {decodedSubject}");

// Process email attachment and work with temporary file
var handler = new EmailAttachmentHandler();
var attachment = GetEmailAttachment(); // From email message

var result = handler.ProcessAttachment(attachment);

if (result.IsSuccess)
{
    var tempFile = result.TempFile;

    Console.WriteLine("Temporary file information:");
    Console.WriteLine($"  Original name: {tempFile.OriginalFileName}");
    Console.WriteLine($"  Temporary path: {tempFile.TemporaryFilePath}");
    Console.WriteLine($"  File size: {tempFile.FileSize:N0} bytes");
    Console.WriteLine($"  Content type: {tempFile.ContentType}");
    Console.WriteLine($"  Created at: {tempFile.CreatedAt:yyyy-MM-dd HH:mm:ss}");
    Console.WriteLine($"  Is disposed: {tempFile.IsDisposed}");

    // Different ways to read content
    if (tempFile.ContentType.StartsWith("text/"))
    {
        // Read as text with automatic encoding detection
        string textContent = tempFile.ReadAsText();
        Console.WriteLine($"Text content preview: {textContent.Substring(0, Math.Min(200, textContent.Length))}...");

        // Read as text with specific encoding
        string utf8Content = tempFile.ReadAsText(Encoding.UTF8);
        Console.WriteLine($"UTF-8 content length: {utf8Content.Length} characters");
    }

    // Read as binary data
    byte[] binaryContent = tempFile.ReadAllBytes();
    Console.WriteLine($"Binary content: {binaryContent.Length:N0} bytes");

    // Work with file stream
    using (var stream = tempFile.OpenRead())
    {
        Console.WriteLine($"Stream length: {stream.Length:N0} bytes");
        Console.WriteLine($"Stream position: {stream.Position}");

        // Read first few bytes to determine file type
        byte[] header = new byte[16];
        int bytesRead = stream.Read(header, 0, header.Length);

        Console.WriteLine($"File header: {BitConverter.ToString(header, 0, bytesRead)}");

        // Identify common file types by header
        string fileType = IdentifyFileType(header, bytesRead);
        Console.WriteLine($"Detected file type: {fileType}");
    }

    // Copy to permanent location
    string permanentPath = @"C:\SavedAttachments\" + SanitizeFileName(tempFile.OriginalFileName);
    Directory.CreateDirectory(Path.GetDirectoryName(permanentPath));

    File.Copy(tempFile.TemporaryFilePath, permanentPath, overwrite: true);
    Console.WriteLine($"Copied to permanent location: {permanentPath}");

    // Verify copy
    if (File.Exists(permanentPath))
    {
        var permanentFileInfo = new FileInfo(permanentPath);
        Console.WriteLine($"Permanent file size: {permanentFileInfo.Length:N0} bytes");

        if (permanentFileInfo.Length == tempFile.FileSize)
        {
            Console.WriteLine("✓ File copied successfully");
        }
        else
        {
            Console.WriteLine("✗ File copy verification failed - size mismatch");
        }
    }

    // Temporary file is automatically cleaned up when handler is disposed
    // or can be manually disposed
    tempFile.Dispose();
    Console.WriteLine($"Temporary file disposed: {tempFile.IsDisposed}");
}

string IdentifyFileType(byte[] header, int length)
{
    if (length < 4) return "Unknown";

    // PDF
    if (header[0] == 0x25 && header[1] == 0x50 && header[2] == 0x44 && header[3] == 0x46)
        return "PDF Document";

    // ZIP (includes DOCX, XLSX, etc.)
    if (header[0] == 0x50 && header[1] == 0x4B)
        return "ZIP Archive (possibly Office document)";

    // JPEG
    if (header[0] == 0xFF && header[1] == 0xD8)
        return "JPEG Image";

    // PNG
    if (header[0] == 0x89 && header[1] == 0x50 && header[2] == 0x4E && header[3] == 0x47)
        return "PNG Image";

    // Text file (common text characters)
    if (header.Take(length).All(b => b >= 32 && b <= 126 || b == 9 || b == 10 || b == 13))
        return "Text File";

    return "Binary File";
}

string SanitizeFileName(string fileName)
{
    if (string.IsNullOrEmpty(fileName))
        return "attachment";

    // Replace invalid characters
    char[] invalidChars = Path.GetInvalidFileNameChars();
    string sanitized = fileName;

    foreach (char c in invalidChars)
    {
        sanitized = sanitized.Replace(c, '_');
    }

    // Ensure unique filename
    return $"{DateTime.Now:yyyyMMdd_HHmmss}_{sanitized}";
}

using ByteForge.Toolkit;
using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Net.Mail;
using System.Text;
using System.Threading.Tasks;

// Enterprise email processing service
public class EnterpriseEmailProcessor
{
    private readonly EmailAttachmentHandler _attachmentHandler;
    private readonly ILogger _logger;
    private readonly EmailProcessingConfig _config;

    public EnterpriseEmailProcessor(ILogger logger, EmailProcessingConfig config)
    {
        _logger = logger;
        _config = config;
        _attachmentHandler = new EmailAttachmentHandler();
    }

    public async Task<EmailProcessingResult> ProcessEmailAsync(MailMessage email)
    {
        var result = new EmailProcessingResult
        {
            EmailId = email.Headers["Message-ID"] ?? Guid.NewGuid().ToString(),
            ProcessedAt = DateTime.UtcNow,
            From = email.From?.Address,
            Subject = email.Subject
        };

        try
        {
            _logger.Info($"Processing email: {result.EmailId}");
            _logger.Info($"  From: {result.From}");
            _logger.Info($"  Subject: {result.Subject}");
            _logger.Info($"  Attachments: {email.Attachments.Count}");

            // Validate sender
            if (!IsAuthorizedSender(email.From))
            {
                result.Status = ProcessingStatus.Rejected;
                result.ErrorMessage = "Sender not authorized";
                _logger.Warning($"Rejected email from unauthorized sender: {email.From}");
                return result;
            }

            // Process email headers
            ProcessEmailHeaders(email, result);

            // Process attachments if any
            if (email.Attachments.Any())
            {
                await ProcessAttachmentsAsync(email.Attachments, result);
            }

            // Process email body
            ProcessEmailBody(email, result);

            // Save email metadata
            await SaveEmailMetadataAsync(result);

            result.Status = ProcessingStatus.Completed;
            _logger.Info($"Successfully processed email: {result.EmailId}");

        }
        catch (Exception ex)
        {
            result.Status = ProcessingStatus.Failed;
            result.ErrorMessage = ex.Message;
            result.Exception = ex;
            _logger.Error($"Error processing email {result.EmailId}", ex);
        }

        return result;
    }

    private bool IsAuthorizedSender(MailAddress from)
    {
        if (from == null) return false;

        // Check against whitelist
        return _config.AuthorizedDomains.Any(domain => 
            from.Address.EndsWith($"@{domain}", StringComparison.OrdinalIgnoreCase)) ||
            _config.AuthorizedSenders.Contains(from.Address, StringComparer.OrdinalIgnoreCase);
    }

    private void ProcessEmailHeaders(MailMessage email, EmailProcessingResult result)
    {
        _logger.Debug("Processing email headers");

        // Extract useful headers
        result.MessageId = email.Headers["Message-ID"];
        result.ReceivedDate = DateTime.TryParse(email.Headers["Date"], out var date) ? date : DateTime.UtcNow;
        result.Priority = email.Priority.ToString();

        // Check for special processing instructions
        string processingType = email.Headers["X-Processing-Type"];
        if (!string.IsNullOrEmpty(processingType))
        {
            result.ProcessingInstructions = processingType;
            _logger.Info($"Special processing requested: {processingType}");
        }

        // Validate and decode subject if needed
        if (!string.IsNullOrEmpty(email.Subject))
        {
            try
            {
                result.DecodedSubject = MailUtil.DecodeEmailHeader($"Subject: {email.Subject}");
                if (result.DecodedSubject.StartsWith("Subject: "))
                {
                    result.DecodedSubject = result.DecodedSubject.Substring("Subject: ".Length);
                }
            }
            catch (Exception ex)
            {
                _logger.Warning($"Failed to decode subject: {ex.Message}");
                result.DecodedSubject = email.Subject;
            }
        }
    }

    private async Task ProcessAttachmentsAsync(AttachmentCollection attachments, EmailProcessingResult result)
    {
        _logger.Info($"Processing {attachments.Count} attachments");

        var attachmentResults = new List<AttachmentProcessingResult>();

        foreach (var attachment in attachments)
        {
            var attachmentResult = new AttachmentProcessingResult
            {
                OriginalFileName = attachment.Name,
                ContentType = attachment.ContentType.MediaType,
                Size = attachment.ContentStream.Length
            };

            try
            {
                // Validate attachment
                if (!IsValidAttachment(attachment))
                {
                    attachmentResult.Status = AttachmentStatus.Rejected;
                    attachmentResult.ErrorMessage = "Attachment validation failed";
                    attachmentResults.Add(attachmentResult);
                    continue;
                }

                // Process attachment
                var processResult = _attachmentHandler.ProcessAttachment(attachment);

                if (processResult.IsSuccess)
                {
                    attachmentResult.Status = AttachmentStatus.Processed;
                    attachmentResult.TempFilePath = processResult.TempFile.TemporaryFilePath;

                    // Save to permanent location
                    string permanentPath = await SaveAttachmentAsync(processResult.TempFile, result.EmailId);
                    attachmentResult.SavedPath = permanentPath;

                    _logger.Info($"  ✓ {attachment.Name} -> {permanentPath}");
                }
                else
                {
                    attachmentResult.Status = AttachmentStatus.Failed;
                    attachmentResult.ErrorMessage = processResult.ErrorMessage;
                    _logger.Warning($"  ✗ {attachment.Name}: {processResult.ErrorMessage}");
                }
            }
            catch (Exception ex)
            {
                attachmentResult.Status = AttachmentStatus.Failed;
                attachmentResult.ErrorMessage = ex.Message;
                _logger.Error($"  ✗ {attachment.Name}: Exception during processing", ex);
            }

            attachmentResults.Add(attachmentResult);
        }

        result.Attachments = attachmentResults;
        result.AttachmentCount = attachmentResults.Count;
        result.SuccessfulAttachments = attachmentResults.Count(a => a.Status == AttachmentStatus.Processed);
    }

    private bool IsValidAttachment(Attachment attachment)
    {
        // Check file size
        if (attachment.ContentStream.Length > _config.MaxAttachmentSize)
        {
            _logger.Warning($"Attachment too large: {attachment.Name} ({attachment.ContentStream.Length:N0} bytes)");
            return false;
        }

        // Check file type
        string extension = Path.GetExtension(attachment.Name ?? "").ToLower();
        if (!_config.AllowedExtensions.Contains(extension))
        {
            _logger.Warning($"Attachment type not allowed: {attachment.Name} ({extension})");
            return false;
        }

        // Check for dangerous filenames
        if (IsDangerousFileName(attachment.Name))
        {
            _logger.Warning($"Dangerous filename detected: {attachment.Name}");
            return false;
        }

        return true;
    }

    private bool IsDangerousFileName(string fileName)
    {
        if (string.IsNullOrEmpty(fileName)) return false;

        return fileName.Contains("..") ||  // Directory traversal
               fileName.Contains("\\") ||  // Path separators
               fileName.Contains("/") ||
               Path.GetInvalidFileNameChars().Any(fileName.Contains);
    }

    private async Task<string> SaveAttachmentAsync(TempFileAttachment tempFile, string emailId)
    {
        string dateFolder = DateTime.Now.ToString("yyyy-MM");
        string attachmentDir = Path.Combine(_config.AttachmentStoragePath, dateFolder, emailId);

        Directory.CreateDirectory(attachmentDir);

        string sanitizedFileName = SanitizeFileName(tempFile.OriginalFileName);
        string permanentPath = Path.Combine(attachmentDir, sanitizedFileName);

        // Ensure unique filename
        int counter = 1;
        string basePath = permanentPath;
        while (File.Exists(permanentPath))
        {
            string extension = Path.GetExtension(basePath);
            string nameWithoutExt = Path.GetFileNameWithoutExtension(basePath);
            permanentPath = Path.Combine(Path.GetDirectoryName(basePath), $"{nameWithoutExt}_{counter}{extension}");
            counter++;
        }

        File.Copy(tempFile.TemporaryFilePath, permanentPath);
        return permanentPath;
    }

    private void ProcessEmailBody(MailMessage email, EmailProcessingResult result)
    {
        _logger.Debug("Processing email body");

        result.BodyType = email.IsBodyHtml ? "HTML" : "Plain Text";
        result.BodyLength = email.Body?.Length ?? 0;

        // Extract key information from body
        if (!string.IsNullOrEmpty(email.Body))
        {
            // Look for processing instructions in email body
            var instructions = ExtractProcessingInstructions(email.Body);
            if (instructions.Any())
            {
                result.BodyInstructions = instructions;
                _logger.Info($"Found processing instructions in body: {string.Join(", ", instructions)}");
            }
        }
    }

    private List<string> ExtractProcessingInstructions(string body)
    {
        var instructions = new List<string>();

        // Look for common processing keywords
        var keywords = new[] { "urgent", "priority", "immediate", "batch", "scheduled" };

        foreach (var keyword in keywords)
        {
            if (body.Contains(keyword, StringComparison.OrdinalIgnoreCase))
            {
                instructions.Add(keyword);
            }
        }

        return instructions;
    }

    private async Task SaveEmailMetadataAsync(EmailProcessingResult result)
    {
        string metadataDir = Path.Combine(_config.MetadataStoragePath, DateTime.Now.ToString("yyyy-MM"));
        Directory.CreateDirectory(metadataDir);

        string metadataFile = Path.Combine(metadataDir, $"{result.EmailId}.json");
        string json = System.Text.Json.JsonSerializer.Serialize(result, new JsonSerializerOptions { WriteIndented = true });

        await File.WriteAllTextAsync(metadataFile, json);
    }

    private string SanitizeFileName(string fileName)
    {
        if (string.IsNullOrEmpty(fileName)) return "attachment";

        char[] invalidChars = Path.GetInvalidFileNameChars();
        string sanitized = fileName;

        foreach (char c in invalidChars)
        {
            sanitized = sanitized.Replace(c, '_');
        }

        return sanitized;
    }

    public void Dispose()
    {
        _attachmentHandler?.CleanupTemporaryFiles();
    }
}

// Configuration class
public class EmailProcessingConfig
{
    public List<string> AuthorizedDomains { get; set; } = new();
    public List<string> AuthorizedSenders { get; set; } = new();
    public List<string> AllowedExtensions { get; set; } = new() { ".pdf", ".docx", ".xlsx", ".txt", ".csv" };
    public long MaxAttachmentSize { get; set; } = 50 * 1024 * 1024; // 50 MB
    public string AttachmentStoragePath { get; set; } = @"C:\EmailAttachments";
    public string MetadataStoragePath { get; set; } = @"C:\EmailMetadata";
}

// Result classes
public class EmailProcessingResult
{
    public string EmailId { get; set; }
    public DateTime ProcessedAt { get; set; }
    public string From { get; set; }
    public string Subject { get; set; }
    public string DecodedSubject { get; set; }
    public string MessageId { get; set; }
    public DateTime ReceivedDate { get; set; }
    public string Priority { get; set; }
    public string ProcessingInstructions { get; set; }
    public string BodyType { get; set; }
    public int BodyLength { get; set; }
    public List<string> BodyInstructions { get; set; } = new();
    public List<AttachmentProcessingResult> Attachments { get; set; } = new();
    public int AttachmentCount { get; set; }
    public int SuccessfulAttachments { get; set; }
    public ProcessingStatus Status { get; set; }
    public string ErrorMessage { get; set; }
    public Exception Exception { get; set; }
}

public class AttachmentProcessingResult
{
    public string OriginalFileName { get; set; }
    public string ContentType { get; set; }
    public long Size { get; set; }
    public AttachmentStatus Status { get; set; }
    public string TempFilePath { get; set; }
    public string SavedPath { get; set; }
    public string ErrorMessage { get; set; }
}

public enum ProcessingStatus
{
    Pending,
    Completed,
    Failed,
    Rejected
}

public enum AttachmentStatus
{
    Pending,
    Processed,
    Failed,
    Rejected
}

// Main application
public class EmailProcessingApplication
{
    private readonly EnterpriseEmailProcessor _processor;
    private readonly ILogger _logger;

    public EmailProcessingApplication(ILogger logger)
    {
        _logger = logger;

        var config = new EmailProcessingConfig
        {
            AuthorizedDomains = new() { "company.com", "partner.com", "vendor.com" },
            AuthorizedSenders = new() { "reports@external.com", "data@supplier.com" },
            MaxAttachmentSize = 100 * 1024 * 1024, // 100 MB
            AttachmentStoragePath = @"C:\EmailProcessing\Attachments",
            MetadataStoragePath = @"C:\EmailProcessing\Metadata"
        };

        _processor = new EnterpriseEmailProcessor(logger, config);
    }

    public async Task RunAsync()
    {
        _logger.Info("Starting enterprise email processing application");

        try
        {
            // Get emails from server (implementation depends on email provider)
            var emails = await GetEmailsFromServerAsync();

            _logger.Info($"Retrieved {emails.Count} emails for processing");

            var results = new List<EmailProcessingResult>();

            foreach (var email in emails)
            {
                var result = await _processor.ProcessEmailAsync(email);
                results.Add(result);
            }

            // Generate summary report
            GenerateProcessingSummary(results);

            _logger.Info("Email processing completed successfully");
        }
        catch (Exception ex)
        {
            _logger.Fatal("Email processing application failed", ex);
            throw;
        }
        finally
        {
            _processor.Dispose();
        }
    }

    private async Task<List<MailMessage>> GetEmailsFromServerAsync()
    {
        // Placeholder - implement actual email retrieval
        // This would typically use POP3, IMAP, or Exchange Web Services
        return new List<MailMessage>();
    }

    private void GenerateProcessingSummary(List<EmailProcessingResult> results)
    {
        var summary = new StringBuilder();
        summary.AppendLine("Email Processing Summary");
        summary.AppendLine("=======================");
        summary.AppendLine($"Total emails: {results.Count}");
        summary.AppendLine($"Successful: {results.Count(r => r.Status == ProcessingStatus.Completed)}");
        summary.AppendLine($"Failed: {results.Count(r => r.Status == ProcessingStatus.Failed)}");
        summary.AppendLine($"Rejected: {results.Count(r => r.Status == ProcessingStatus.Rejected)}");
        summary.AppendLine($"Total attachments: {results.Sum(r => r.AttachmentCount)}");
        summary.AppendLine($"Successful attachments: {results.Sum(r => r.SuccessfulAttachments)}");

        _logger.Info($"Processing Summary:\n{summary}");
    }
}

// Program entry point
public class Program
{
    static async Task Main(string[] args)
    {
        var logger = new ConsoleLogger(); // Use actual logging framework
        var app = new EmailProcessingApplication(logger);

        try
        {
            await app.RunAsync();
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Application failed: {ex.Message}");
            Environment.Exit(1);
        }
    }
}

// Simple logger for example
public interface ILogger
{
    void Debug(string message);
    void Info(string message);
    void Warning(string message);
    void Error(string message, Exception ex = null);
    void Fatal(string message, Exception ex = null);
}

public class ConsoleLogger : ILogger
{
    public void Debug(string message) => Console.WriteLine($"[DEBUG] {message}");
    public void Info(string message) => Console.WriteLine($"[INFO] {message}");
    public void Warning(string message) => Console.WriteLine($"[WARN] {message}");
    public void Error(string message, Exception ex = null) => Console.WriteLine($"[ERROR] {message}" + (ex != null ? $" - {ex.Message}" : ""));
    public void Fatal(string message, Exception ex = null) => Console.WriteLine($"[FATAL] {message}" + (ex != null ? $" - {ex.Message}" : ""));
}
